
"use client";

import { useState, useEffect } from "react";
import Image from 'next/image';
import Link from 'next/link';
import {
  Home,
  FileText,
  CalendarCheck,
  FlaskConical,
  History,
  Settings,
  Library,
  LogOut,
  Users,
  Search
} from 'lucide-react';
import { usePathname } from "next/navigation";
import { useAuth } from "@/contexts/AuthContext";
import { addAuditLogAction, getAuditLogsAction } from "@/app/actions/dbActions";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { AuditLog } from "@/utils/storage";


const AdminSidebar = () => {
    const { user, logout } = useAuth();
    const pathname = usePathname();

    const handleLogout = async () => {
        if(user) {
            await addAuditLogAction({ userId: user.id, userName: user.name, action: 'logout' });
        }
        logout();
    };

    const sidebarNavItems = [
        { title: 'Dashboard', icon: Home, href: '/dashboard' },
        { title: 'User Management', icon: Users, href: '/admin/users' },
        { title: 'Request Management', icon: FileText, href: '/admin/requests' },
        { title: 'Attendance Report', icon: CalendarCheck, href: '/admin/reports' },
        { title: 'LAB Management', icon: FlaskConical, href: '/admin/labs' },
        { title: 'Library', icon: Library, href: '/admin/library' },
        { title: 'Audit Log', icon: History, href: '/admin/audit' },
        { title: 'System Settings', icon: Settings, href: '/admin/settings' },
    ];

    return (
        <aside className="w-64 bg-white p-5 flex flex-col border-r">
            <div className="text-center mb-6 mt-2">
                <Link href="/profile">
                    <div className="w-16 h-16 rounded-md bg-primary text-white flex items-center justify-center mx-auto mb-3 cursor-pointer">
                        <span className="text-2xl font-bold">{user?.name?.charAt(0) || 'A'}</span>
                    </div>
                </Link>
                <h3 className="font-semibold text-gray-800">Administrator</h3>
                <p className="text-sm text-muted-foreground">{user?.name}</p>
            </div>

            <nav className="flex-grow space-y-2">
                {sidebarNavItems.map((item) => {
                    const isActive = pathname === item.href;
                    return (
                        <Link key={item.title} href={item.href} passHref>
                            <Button
                                variant={isActive ? 'default' : 'ghost'}
                                className={`w-full justify-start gap-3 text-base font-medium ${isActive ? 'text-white' : 'text-gray-600 hover:text-primary hover:bg-primary/5'}`}
                                style={isActive ? { backgroundColor: '#E30613' } : {}}
                            >
                                <item.icon className={`w-5 h-5 ${isActive ? 'text-white' : 'text-gray-400 group-hover:text-primary'}`} />
                                {item.title}
                            </Button>
                        </Link>
                    )
                })}
            </nav>
            
            <div className="mt-auto">
                <Button onClick={handleLogout} variant="ghost" className="w-full justify-start gap-3 text-base font-medium text-red-500 hover:text-red-700 hover:bg-red-50">
                    <LogOut className="w-5 h-5" />
                    Logout
                </Button>
            </div>
        </aside>
    );
}

export default function AuditLogPage() {
    const [logs, setLogs] = useState<AuditLog[]>([]);
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        const fetchLogs = async () => {
            const auditLogs = await getAuditLogsAction();
            setLogs(auditLogs.reverse());
        };
        fetchLogs();
    }, []);

    const filteredLogs = logs.filter(log =>
        log.userName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        log.userId.toLowerCase().includes(searchTerm.toLowerCase()) ||
        log.action.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col">
            <header className="bg-primary shadow-lg sticky top-0 z-20">
                <div className="mx-auto px-8 h-16 flex items-center">
                    <Image src="/logo.png" alt="AMA Student Portal" width={150} height={38} priority />
                </div>
            </header>
            <div className="flex flex-1">
                <AdminSidebar />
                <main className="flex-1 p-8 overflow-y-auto">
                    <div className="mb-8">
                        <h1 className="text-3xl font-bold text-gray-800">Audit Log</h1>
                        <p className="text-muted-foreground">Track user sign-in and sign-out activities.</p>
                    </div>

                    <div className="relative mb-6 max-w-sm">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
                        <Input 
                            placeholder="Search logs..." 
                            className="pl-10"
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                        />
                    </div>
                    
                    <Card>
                        <CardContent className="pt-6">
                            <Table>
                                <TableHeader>
                                    <TableRow>
                                        <TableHead>Timestamp</TableHead>
                                        <TableHead>User</TableHead>
                                        <TableHead>Action</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {filteredLogs.map(log => (
                                        <TableRow key={log.id}>
                                            <TableCell>{new Date(log.timestamp).toLocaleString()}</TableCell>
                                            <TableCell>
                                                <div className="font-medium">{log.userName}</div>
                                                <div className="text-sm text-muted-foreground">{log.userId}</div>
                                            </TableCell>
                                            <TableCell>
                                                <span className={`capitalize px-2 py-1 rounded-full text-xs font-semibold ${log.action === 'login' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
                                                    {log.action}
                                                </span>
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                    {filteredLogs.length === 0 && (
                                        <TableRow>
                                            <TableCell colSpan={3} className="text-center text-muted-foreground py-10">No logs found.</TableCell>
                                        </TableRow>
                                    )}
                                </TableBody>
                            </Table>
                        </CardContent>
                    </Card>
                </main>
            </div>
        </div>
    );
}

